118→const assertCanvasJournalAccess = async(journalId, viewerId = null) => {
119→    if(!journalId){
120→        throw {status: 400, error: 'journalId is undefined'};
121→    }
122→
123→    const {data: journal, error: journalError} = await supabase
124→    .from('journals')
125→    .select('id, user_id, title, post_type, canvas_doc, privacy')
126→    .eq('id', journalId)
127→    .maybeSingle();
128→
129→    if(journalError){
130→        console.error('supabase error while fetching canvas journal', journalError.message);
131→        throw {status: 500, error: 'supabase error while fetching canvas journal'};
132→    }
133→
134→    if(!journal){
135→        throw {status: 404, error: 'journal not found'};
136→    }
137→
138→    if(journal.post_type !== POST_TYPE_CANVAS){
139→        throw {status: 400, error: 'journal is not a canvas post'};
140→    }
141→
142→    const isOwner = viewerId && journal.user_id === viewerId;
143→    if(journal.privacy === 'private' && !isOwner){
144→        throw {status: 403, error: 'canvas journal is private'};
145→    }
146→
147→    return journal;
