189→export const uploadJournalContentService = async(
190→    content,
191→    title,
192→    userId,
193→    postType = POST_TYPE_TEXT,
194→    canvasDocInput = null,
195→    remixSourceJournalId = null,
196→    isRemix = false
197→) =>{
198→    if(!userId){
199→        console.error('userId is undefined');
200→        throw {status: 400, error: 'userId is undefined'};
201→    }
202→
203→    const resolvedPostType = normalizePostType(postType);
204→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
205→
206→    if(!trimmedTitle){
207→        console.error('title is missing!');
208→        throw {status: 400, error: 'title is missing!'};
209→    }
210→
211→    let embeddingBody = '';
212→    const shouldSaveRemixMetadata = Boolean(
213→        remixSourceJournalId
214→        && typeof remixSourceJournalId === 'string'
215→        && remixSourceJournalId.trim()
216→    );
217→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
218→    let payload = {
219→        user_id: userId,
220→        title: trimmedTitle,
221→        post_type: resolvedPostType
222→    };
223→
224→    if(resolvedPostType === POST_TYPE_CANVAS){
225→        let parsedCanvasDoc = null;
226→        try {
227→            parsedCanvasDoc = parseCanvasDocInput(canvasDocInput);
228→        } catch (error) {
229→            console.error('invalid canvas doc on insert:', error?.message || error);
230→            throw {status: 400, error: 'invalid canvas_doc'};
231→        }
232→
233→        if(!parsedCanvasDoc){
234→            console.error('canvas_doc is missing for canvas post');
235→            throw {status: 400, error: 'canvas_doc is missing'};
236→        }
237→
238→        embeddingBody = extractCanvasPlainText(parsedCanvasDoc);
239→        payload = {
240→            ...payload,
241→            content: null,
242→            canvas_doc: parsedCanvasDoc
243→        };
244→    } else {
245→        if(!content){
246→            console.error('content is missing for text post!');
247→            throw {status: 400, error: 'content is missing for text post'};
248→        }
249→
250→        const parseData = parseTextContentSafely(content);
251→        if(!parseData){
252→            console.error('error while parsing text content data');
253→            throw {status: 400, error: 'error while parsing text content data'};
254→        }
255→
256→        embeddingBody = parseData.wholeText || '';
257→        payload = {
258→            ...payload,
259→            content: content,
260→            canvas_doc: null
261→        };
262→    }
263→
264→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
265→
266→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
267→        console.error('error while generating embeddings on a post!');
268→        throw {status: 400, error: 'error while generating embeddings on a post!'};
269→    }
270→
271→    const insertPayload = {
272→        ...payload,
273→        embeddings: embeddingResult
274→    };
275→
276→    if(normalizedIsRemix){
277→        insertPayload.is_remix = true;
278→    }
279→    if(shouldSaveRemixMetadata){
280→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
281→    }
282→
283→    let {error} = await supabase
284→    .from('journals')
285→    .insert(insertPayload);
286→
287→    if(error){
288→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
289→        if(missingRemixColumns){
290→            const fallbackPayload = {
291→                ...payload,
292→                embeddings: embeddingResult
293→            };
294→
295→            const retry = await supabase
296→            .from('journals')
297→            .insert(fallbackPayload);
298→            error = retry.error;
299→        }
300→    }
301→
302→    if(error){
303→        console.error('supabase error while uploading content:',error.message);
304→        throw {status: 500, error: 'supabase error while uploading content'};
