239→    const offsets = {...cursorState.offsets};
240→    const exhausted = {...cursorState.exhausted};
241→    const pending = Array.isArray(cursorState.pending) ? [...cursorState.pending] : [];
242→    const unavailableBuckets = [];
243→    const maxIterations = 6;
244→    let iterationCount = 0;
245→
246→    while(
247→        pending.length < parsedLimit &&
248→        PROFILE_MEDIA_BUCKETS.some((bucket) => !exhausted[bucket]) &&
249→        iterationCount < maxIterations
250→    ){
251→        iterationCount += 1;
252→        const activeBuckets = PROFILE_MEDIA_BUCKETS.filter((bucket) => !exhausted[bucket]);
253→        const chunkResults = await Promise.all(
254→            activeBuckets.map((bucket) => listMediaChunkForBucket(bucket, userId, offsets[bucket] || 0, parsedLimit))
255→        );
256→
257→        chunkResults.forEach((result) => {
258→            offsets[result.bucket] = result.nextOffset;
259→            exhausted[result.bucket] = result.exhausted;
260→
261→            if(result.error){
262→                console.error(`supabase storage list error on ${result.bucket}:`, result.error);
263→                unavailableBuckets.push(result.bucket);
264→                return;
265→            }
266→
267→            pending.push(...result.items);
268→        });
